     4â†’import { IStylesMvBase } from '@modules/db/styles-mv/types/styles-mv.base.interface';
     5â†’import { EnvConfigService } from '@modules/env-config/env-config.service';
     6â†’import { OpensearchService } from '@modules/opensearch/opensearch.service';
     7â†’
     8â†’import {
     9â†’	NEURAL_SEARCH_LIMIT,
    10â†’	NEURAL_SEARCH_MAX_QUERY_LENGTH,
    11â†’} from '@constants/common.constant';
    12â†’import { OPENSEARCH_CONVERSATIONAL_INDEX_NAME } from '@constants/env-variables.constant';
    13â†’import { NEURAL_SEARCH_KNOWN_BRANDS } from '@constants/neural-search-brands.constant';
    14â†’
    15â†’import { IOpensearchProduct } from '@interfaces/opensearch-product.interface';
    16â†’
    17â†’import { LogExecution } from '@decorators/log-execution.decorator';
    18â†’
    19â†’const MODEL_REFRESH_INTERVAL_MS = 5 * 60 * 1000;
    20â†’
    21â†’const MODEL_GROUP_NAME = 'conversational-search-model-group';
    22â†’
    23â†’const EMBEDDING_MODEL_PARTIAL_NAME = 'all-distilroberta';
    24â†’const LLM_MODEL_PARTIAL_NAME = 'gpt';
    25â†’
    26â†’@Injectable()
    27â†’export class OpensearchConversationalService implements OnModuleInit {
    28â†’	private readonly logger = new Logger(OpensearchConversationalService.name);
    29â†’	private indexName: string;
    30â†’	private embeddingModelId: string | null = null;
    31â†’	private llmModelId: string | null = null;
    32â†’
    33â†’	constructor(
    34â†’		private readonly opensearchService: OpensearchService,
    35â†’		private readonly configService: EnvConfigService,
    36â†’	) {}
    37â†’
    38â†’	async onModuleInit(): Promise<void> {
    39â†’		this.indexName = this.configService.get<string>({
    40â†’			key: OPENSEARCH_CONVERSATIONAL_INDEX_NAME,
    41â†’		});
    42â†’		await this.resolveModelIds();
    43â†’	}
    44â†’
    45â†’	@Interval(MODEL_REFRESH_INTERVAL_MS)
    46â†’	async refreshModelIds(): Promise<void> {
    47â†’		await this.resolveModelIds();
    48â†’	}
    49â†’
    50â†’	private async resolveModelIds(): Promise<void> {
    51â†’		try {
    52â†’			const modelGroupId = await this.opensearchService.searchModelGroupByName({
    53â†’				name: MODEL_GROUP_NAME,
    54â†’			});
    55â†’
    56â†’			if (!modelGroupId) {
    57â†’				this.logger.warn(
    58â†’					'Conversational search model group not found. Run: npm run cli:dev -- bootstrap-conversational-search',
    59â†’				);
    60â†’				return;
    61â†’			}
    62â†’
    63â†’			const models = await this.opensearchService.searchModelsByGroupWithNames({
    64â†’				modelGroupId,
    65â†’			});
    66â†’
    67â†’			const deployedModels = models.filter((m) => m.model_state === 'DEPLOYED');
    68â†’
    69â†’			const embeddingModel = deployedModels.find((m) =>
    70â†’				m.name.toLowerCase().includes(EMBEDDING_MODEL_PARTIAL_NAME),
    71â†’			);
    72â†’			const llmModel = deployedModels.find((m) =>
    73â†’				m.name.toLowerCase().includes(LLM_MODEL_PARTIAL_NAME),
    74â†’			);
    75â†’
    76â†’			if (embeddingModel && embeddingModel.model_id !== this.embeddingModelId) {
    77â†’				const previous = this.embeddingModelId;
    78â†’				this.embeddingModelId = embeddingModel.model_id;
    79â†’				this.logger.log(
    80â†’					`Embedding model ID updated: ${previous ?? 'none'} -> ${embeddingModel.model_id}`,
    81â†’				);
    82â†’			}
    83â†’
    84â†’			if (llmModel && llmModel.model_id !== this.llmModelId) {
    85â†’				const previous = this.llmModelId;
    86â†’				this.llmModelId = llmModel.model_id;
    87â†’				this.logger.log(
    88â†’					`LLM model ID updated: ${previous ?? 'none'} -> ${llmModel.model_id}`,
    89â†’				);
    90â†’			}
    91â†’
    92â†’			if (!embeddingModel || !llmModel) {
    93â†’				this.logger.warn(
    94â†’					'Not all conversational search models are deployed. Run bootstrap first.',
    95â†’				);
    96â†’			}
    97â†’		} catch {
    98â†’			this.logger.warn(
    99â†’				'Failed to resolve conversational model IDs. OpenSearch may not be available.',
   100â†’			);
   101â†’		}
   102â†’	}
   103â†’
   104â†’	getEmbeddingModelId(): string {
   105â†’		if (!this.embeddingModelId) {
   106â†’			throw new Error(
   107â†’				'Conversational embedding model not available. Run: npm run cli:dev -- bootstrap-conversational-search',
   108â†’			);
   109â†’		}
   110â†’		return this.embeddingModelId;
   111â†’	}
   112â†’
   113â†’	getLlmModelId(): string {
   114â†’		if (!this.llmModelId) {
   115â†’			throw new Error(
   116â†’				'Conversational LLM model not available. Run: npm run cli:dev -- bootstrap-conversational-search',
   117â†’			);
   118â†’		}
   119â†’		return this.llmModelId;
   120â†’	}
