   122â†’	private detectBrand({ text }: { text: string }): string | null {
   123â†’		const sorted = [...NEURAL_SEARCH_KNOWN_BRANDS].sort((a, b) => b.length - a.length);
   124â†’		for (const brand of sorted) {
   125â†’			const escaped = brand.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
   126â†’			if (new RegExp(`\\b${escaped}\\b`, 'i').test(text)) {
   127â†’				return brand;
   128â†’			}
   129â†’		}
   130â†’		return null;
   131â†’	}
   132â†’
   133â†’	private readonly GENDER_PRODUCT_TYPE_MAP: {
   134â†’		pattern: RegExp;
   135â†’		productTypes: string[];
   136â†’	}[] = [
   137â†’		{
   138â†’			pattern: /\b(women|woman|womens|women's|female|ladies|lady|girls|girl's)\b/i,
   139â†’			productTypes: ["Women's"],
   140â†’		},
   141â†’		{
   142â†’			pattern: /\b(men|man|mens|men's|male|guys|guy)\b/i,
   143â†’			productTypes: ['Unisex'],
   144â†’		},
   145â†’		{
   146â†’			pattern: /\b(youth|kids|kid|children|child|toddler|infant|baby|juvenile)\b/i,
   147â†’			productTypes: ['Youth'],
   148â†’		},
   149â†’	];
   150â†’
   151â†’	detectGenderProductTypes({ text }: { text: string }): string[] | null {
   152â†’		const productTypes: string[] = [];
   153â†’
   154â†’		for (const { pattern, productTypes: types } of this.GENDER_PRODUCT_TYPE_MAP) {
   155â†’			if (pattern.test(text)) {
   156â†’				productTypes.push(...types);
   157â†’			}
   158â†’		}
   159â†’
   160â†’		return productTypes.length > 0 ? productTypes : null;
   161â†’	}
   162â†’
   163â†’	private readonly PRICE_LEVEL_MAP: { pattern: RegExp; levels: number[] }[] = [
   164â†’		{
   165â†’			pattern:
   166â†’				/\b(cheap|budget|affordable|inexpensive|low[\s-]cost|economical|bargain|value|discount|basic|entry[\s-]level)\b/i,
   167â†’			levels: [1],
   168â†’		},
   169â†’		{
   170â†’			pattern:
   171â†’				/\b(mid[\s-]range|midrange|moderate|average|standard|medium|middle|reasonable|fair price|mid price)\b/i,
   172â†’			levels: [2],
   173â†’		},
   174â†’		{
   175â†’			pattern:
   176â†’				/\b(premium|luxury|high[\s-]end|expensive|upscale|top[\s-]tier|deluxe|elite|designer|exclusive|finest)\b/i,
   177â†’			levels: [3],
   178â†’		},
   179â†’	];
   180â†’
   181â†’	detectPriceLevels({ text }: { text: string }): number[] | null {
   182â†’		const levels: number[] = [];
   183â†’
   184â†’		for (const { pattern, levels: priceLevels } of this.PRICE_LEVEL_MAP) {
   185â†’			if (pattern.test(text)) {
   186â†’				levels.push(...priceLevels);
   187â†’			}
   188â†’		}
   189â†’
   190â†’		return levels.length > 0 ? levels : null;
   191â†’	}
   192â†’
   193â†’	sanitizeQuery({ text }: { text: string }): string {
   194â†’		return text
   195â†’			.trim()
   196â†’			.replace(/<[^>]*>/g, ' ')
   197â†’			.replace(/[\x00-\x1F\x7F]/g, ' ')
   198â†’			.replace(/[^a-zA-Z0-9\s\-'&]/g, ' ')
   199â†’			.replace(/\s{2,}/g, ' ')
   200â†’			.substring(0, NEURAL_SEARCH_MAX_QUERY_LENGTH)
   201â†’			.trim();
   202â†’	}
   203â†’
   204â†’	private readonly QUERY_SYNONYMS: [RegExp, string][] = [
   205â†’		[/\btshirt(s)?\b/gi, 't-shirt$1'],
   206â†’		[/\bt shirt(s)?\b/gi, 't-shirt$1'],
   207â†’		[/\bv[\s-]?neck\b/gi, 'v-neck'],
   208â†’		[/\bcrew[\s-]?neck\b/gi, 'crewneck'],
   209â†’		[/\blong[\s-]?sleeve(s)?\b/gi, 'long-sleeve$1'],
   210â†’		[/\bshort[\s-]?sleeve(s)?\b/gi, 'short-sleeve$1'],
   211â†’		[/\bpolo[\s-]?shirt(s)?\b/gi, 'polo t-shirt$1'],
   212â†’		[/\bsweat[\s-]?shirt(s)?\b/gi, 'sweatshirt$1'],
   213â†’		[/\bsweat[\s-]?pant(s)?\b/gi, 'sweatpant$1'],
   214â†’		[/\bzip[\s-]?up(s)?\b/gi, 'zip-up$1'],
   215â†’		[/\bhalf[\s-]?zip(s)?\b/gi, 'half-zip$1'],
   216â†’		[/\btote[\s-]?bag(s)?\b/gi, 'tote bag$1'],
   217â†’		[/\bdri[\s-]?fit\b/gi, 'dri-fit'],
   218â†’		[/\bslim[\s-]?fit\b/gi, 'slim fit'],
   219â†’		[/\btank[\s-]?top(s)?\b/gi, 'tank top$1'],
   220â†’	];
   221â†’
   222â†’	normalizeQuery({ text }: { text: string }): string {
   223â†’		let normalized = text.toLowerCase().trim();
   224â†’
   225â†’		for (const [pattern, replacement] of this.QUERY_SYNONYMS) {
   226â†’			normalized = normalized.replace(pattern, replacement);
   227â†’		}
   228â†’
   229â†’		return normalized;
   230â†’	}
