   236â†’			number_of_replicas: 1,
   237â†’			'index.knn': true,
   238â†’			'index.knn.algo_param.ef_search': 512,
   239â†’			default_pipeline: 'products-conversational-pipeline',
   240â†’		};
   241â†’
   242â†’		const mappings = {
   243â†’			properties: {
   244â†’				style_id: { type: 'long' },
   245â†’				product_id: { type: 'long' },
   246â†’				name: { type: 'text' },
   247â†’				features: { type: 'text' },
   248â†’				general_comments: { type: 'text' },
   249â†’				decoration_method: { type: 'text' },
   250â†’				manufacturer: { type: 'text' },
   251â†’				primary_category_id: { type: 'integer' },
   252â†’				primary_category_name: { type: 'keyword' },
   253â†’				product_type: { type: 'keyword' },
   254â†’				style_type: { type: 'keyword' },
   255â†’				broad_category_names: { type: 'keyword' },
   256â†’				sub_category_names: { type: 'keyword' },
   257â†’				minimum_quantity: { type: 'integer' },
   258â†’				min_qty: { type: 'integer' },
   259â†’				default_quote_qty: { type: 'integer' },
   260â†’				sizes: { type: 'keyword' },
   261â†’				turn_time: { type: 'integer' },
   262â†’				rush_turn_time: { type: 'integer' },
   263â†’				no_minimum: { type: 'byte' },
   264â†’				price_level: { type: 'short' },
   265â†’				rating_score: { type: 'float' },
   266â†’				rating_count: { type: 'integer' },
   267â†’				default_unit_prices: {
   268â†’					type: 'nested',
   269â†’					properties: {
   270â†’						quantity: { type: 'integer' },
   271â†’						price: { type: 'keyword' },
   272â†’						regular_unit_price: { type: 'keyword' },
   273â†’						algorithm: { type: 'keyword' },
   274â†’					},
   275â†’				},
   276â†’				colors: {
   277â†’					type: 'nested',
   278â†’					properties: {
   279â†’						name: { type: 'keyword' },
   280â†’						id: { type: 'integer' },
   281â†’						rbgs: {
   282â†’							type: 'nested',
   283â†’							properties: {
   284â†’								R: { type: 'short' },
   285â†’								G: { type: 'short' },
   286â†’								B: { type: 'short' },
   287â†’							},
   288â†’						},
   289â†’						image_url: { type: 'keyword' },
   290â†’					},
   291â†’				},
   292â†’				style_card_image_url: { type: 'keyword' },
   293â†’				link: { type: 'keyword' },
   294â†’				brand: { type: 'keyword' },
   295â†’				condensed_features: { type: 'keyword' },
   296â†’				material: { type: 'keyword' },
   297â†’				status: { type: 'keyword' },
   298â†’				created_at: { type: 'date' },
   299â†’				updated_at: { type: 'date' },
   300â†’				deleted_at: { type: 'date' },
   301â†’				combined_text_for_embedding: { type: 'text' },
   302â†’				product_embedding: {
   303â†’					type: 'knn_vector',
   304â†’					dimension: 768,
   305â†’					method: {
   306â†’						name: 'hnsw',
   307â†’						space_type: 'l2',
   308â†’						engine: 'faiss',
   309â†’						parameters: { ef_construction: 512, m: 48 },
   310â†’					},
   311â†’				},
   312â†’			},
