   318â†’	@LogExecution({ logParams: false, logResponse: false })
   319â†’	async bulkIndexProducts({
   320â†’		indexName,
   321â†’		styles,
   322â†’	}: {
   323â†’		indexName: string;
   324â†’		styles: IStylesMvBase[];
   325â†’	}): Promise<{ indexed: number; errors: number }> {
   326â†’		if (styles.length === 0) {
   327â†’			return { indexed: 0, errors: 0 };
   328â†’		}
   329â†’
   330â†’		const documents = styles.map((style) =>
   331â†’			this.transformStyleToOpensearchProduct({ style }),
   332â†’		);
   333â†’
   334â†’		return this.opensearchService.bulkIndex({ indexName, documents });
   335â†’	}
   336â†’
   337â†’	@LogExecution({
   338â†’		paramFormatter: (params: [{ queryText: string; size: number }]) => ({
   339â†’			queryText: params[0].queryText,
   340â†’			size: params[0].size,
   341â†’		}),
   342â†’		responseFormatter: (response: IOpensearchProduct[]) => ({
   343â†’			totalResults: response.length,
   344â†’		}),
   345â†’	})
   346â†’	async searchProducts({
   347â†’		queryText,
   348â†’		size = NEURAL_SEARCH_LIMIT,
   349â†’	}: {
   350â†’		queryText: string;
   351â†’		size?: number;
   352â†’	}): Promise<IOpensearchProduct[]> {
   353â†’		const sanitizedQuery = this.sanitizeQuery({ text: queryText });
   354â†’		const normalizedQuery = this.normalizeQuery({ text: sanitizedQuery });
   355â†’		const genderProductTypes = this.detectGenderProductTypes({ text: sanitizedQuery });
   356â†’		const priceLevels = this.detectPriceLevels({ text: sanitizedQuery });
   357â†’		const brand = this.detectBrand({ text: sanitizedQuery });
   358â†’
   359â†’		const baseFilters: object[] = [{ term: { status: 'active' } }];
   360â†’
   361â†’		if (genderProductTypes) {
   362â†’			baseFilters.push({ terms: { product_type: genderProductTypes } });
   363â†’		}
   364â†’
   365â†’		const priceBoosts: object[] =
   366â†’			priceLevels?.map((level) => ({
   367â†’				term: { price_level: { value: level, boost: 1.5 } },
   368â†’			})) ?? [];
   369â†’
   370â†’		const brandBoosts: object[] = brand ? [{ terms: { brand: [brand], boost: 2 } }] : [];
   371â†’
   372â†’		const hits = await this.opensearchService.search({
   373â†’			indexName: this.indexName,
   374â†’			searchPipeline: 'conversational-hybrid-search-pipeline',
   375â†’			body: {
   376â†’				size,
   377â†’				min_score: 0.4,
   378â†’				query: {
   379â†’					hybrid: {
   380â†’						queries: [
   381â†’							{ bool: { should: [...priceBoosts, ...brandBoosts], filter: baseFilters } },
   382â†’							{
   383â†’								neural: {
   384â†’									product_embedding: {
   385â†’										query_text: normalizedQuery,
   386â†’										model_id: this.getEmbeddingModelId(),
   387â†’										k: size * 5,
   388â†’										filter: { bool: { filter: baseFilters } },
   389â†’									},
   390â†’								},
   391â†’							},
   392â†’						],
   393â†’					},
   394â†’				},
   395â†’				collapse: { field: 'product_id' },
   396â†’				_source: { excludes: ['product_embedding', 'combined_text_for_embedding'] },
   397â†’			},
   398â†’		});
   399â†’
   400â†’		return hits.map((hit) => ({
   401â†’			...(hit._source as IOpensearchProduct),
   402â†’			_id: hit._id,
   403â†’		}));
   404â†’	}
