   406â†’	private normalizeCondensedFeatures({
   407â†’		condensedFeatures,
   408â†’	}: {
   409â†’		condensedFeatures: unknown;
   410â†’	}): string[] | null {
   411â†’		if (condensedFeatures === null || condensedFeatures === undefined) {
   412â†’			return null;
   413â†’		}
   414â†’
   415â†’		if (typeof condensedFeatures === 'string') {
   416â†’			return [condensedFeatures];
   417â†’		}
   418â†’
   419â†’		if (Array.isArray(condensedFeatures)) {
   420â†’			return condensedFeatures.map(String);
   421â†’		}
   422â†’
   423â†’		if (typeof condensedFeatures === 'object') {
   424â†’			return Object.values(condensedFeatures).flatMap((value: unknown) =>
   425â†’				Array.isArray(value) ? value.map(String) : [String(value)],
   426â†’			);
   427â†’		}
   428â†’
   429â†’		return [JSON.stringify(condensedFeatures)];
   430â†’	}
