   432â†’	private buildCombinedTextForEmbedding({ style }: { style: IStylesMvBase }): string {
   433â†’		const normalizedCondensedFeatures = this.normalizeCondensedFeatures({
   434â†’			condensedFeatures: style.condensed_features,
   435â†’		});
   436â†’		const priceLvlMap: Record<string, string> = {
   437â†’			1: 'Budget',
   438â†’			2: 'Mid-range',
   439â†’			3: 'Premium',
   440â†’		};
   441â†’		const mappedPriceLevel: string | null =
   442â†’			style.price_level && priceLvlMap[String(style.price_level)]
   443â†’				? (priceLvlMap[String(style.price_level)] ?? null)
   444â†’				: (priceLvlMap['2'] ?? null);
   445â†’
   446â†’		const parts: string[] = [
   447â†’			...(style.name ? [this.cleanText({ text: style.name })] : []),
   448â†’			...(style.product_type ? [this.cleanText({ text: style.product_type })] : []),
   449â†’			...(mappedPriceLevel ? [`Price lvl: ${mappedPriceLevel}`] : []),
   450â†’			...(style.brand?.length
   451â†’				? [`Brand: ${this.cleanText({ text: style.brand[0] })}`]
   452â†’				: []),
   453â†’			...(normalizedCondensedFeatures?.length
   454â†’				? [this.cleanText({ text: normalizedCondensedFeatures.join(', ') })]
   455â†’				: []),
   456â†’			...(style.style_type ? [this.cleanText({ text: style.style_type })] : []),
   457â†’			...(style.primary_category_name
   458â†’				? [`Category: ${this.cleanText({ text: style.primary_category_name })}`]
   459â†’				: []),
   460â†’			...(style.manufacturer
   461â†’				? [`From: ${this.cleanText({ text: style.manufacturer })}`]
   462â†’				: []),
   463â†’			...(style.sub_category_names?.length
   464â†’				? [
   465â†’						`Subcategories: ${this.cleanText({ text: style.sub_category_names.join(', ') })}`,
   466â†’					]
   467â†’				: []),
   468â†’			...(style.decoration_method
   469â†’				? [`Decoration: ${this.cleanText({ text: style.decoration_method })}`]
   470â†’				: []),
   471â†’			...(style.features
   472â†’				? [`Features: ${this.cleanText({ text: style.features })}`]
