   255â†’				.map((p) => `- ${p.name} (${p.product_type ?? 'product'})`)
   256â†’				.join('\n');
   257â†’
   258â†’			const clarificationContext = clarifications?.length
   259â†’				? `Customer preferences: ${clarifications.map((c) => `${c.questionId}: ${c.answer}`).join(', ')}.`
