   336â†’	private async processBatches({
   337â†’		batches,
   338â†’		concurrency,
   339â†’		indexName,
   340â†’		progressBar,
   341â†’		onBatchComplete,
   342â†’	}: {
   343â†’		batches: { offset: number; limit: number }[];
   344â†’		concurrency: number;
   345â†’		indexName: string;
   346â†’		progressBar: ProgressBar;
   347â†’		onBatchComplete: (indexed: number, errors: number) => void;
   348â†’	}): Promise<void> {
   349â†’		await runWithConcurrencyLimit({
   350â†’			items: batches,
   351â†’			concurrency,
   352â†’			handler: async (batch) => {
   353â†’				if (this.isCancelled) {
   354â†’					return { indexed: 0, errors: 0 };
   355â†’				}
   356â†’
   357â†’				const styles = await this.stylesMvModel.findAll({
   358â†’					limit: batch.limit,
   359â†’					offset: batch.offset,
   360â†’				});
   361â†’
   362â†’				if (styles.length === 0) {
   363â†’					return { indexed: 0, errors: 0 };
   364â†’				}
   365â†’
   366â†’				return this.opensearchConversationalService.bulkIndexProducts({
   367â†’					indexName,
   368â†’					styles,
   369â†’				});
   370â†’			},
   371â†’			onItemComplete: (result) => {
   372â†’				progressBar.increment(result.indexed + result.errors);
   373â†’				onBatchComplete(result.indexed, result.errors);
   374â†’			},
   375â†’			onItemError: (error) => {
   376â†’				this.logger.error(`Batch processing error: ${(error as Error).message}`);
   377â†’			},
   378â†’		});
   379â†’	}
