   426â†’	private setupGracefulShutdown(): void {
   427â†’		const signals: NodeJS.Signals[] = ['SIGTERM', 'SIGINT', 'SIGHUP', 'SIGQUIT'];
   428â†’
   429â†’		signals.forEach((signal) => {
   430â†’			process.on(signal, () => {
   431â†’				void this.handleShutdown(signal);
   432â†’			});
   433â†’		});
   434â†’
   435â†’		process.on('uncaughtException', (error) => {
   436â†’			this.logger.error(`Uncaught exception: ${error.message}`);
   437â†’			void this.handleShutdown('SIGTERM');
   438â†’		});
   439â†’
   440â†’		process.on('unhandledRejection', (reason) => {
   441â†’			this.logger.error(`Unhandled rejection: ${String(reason)}`);
   442â†’			void this.handleShutdown('SIGTERM');
   443â†’		});
   444â†’	}
