   102â†’		indexName,
   103â†’		documents,
   104â†’	}: {
   105â†’		indexName: string;
   106â†’		documents: { _id: string; [key: string]: unknown }[];
   107â†’	}): Promise<{ indexed: number; errors: number }> {
   108â†’		try {
   109â†’			if (documents.length === 0) {
   110â†’				return { indexed: 0, errors: 0 };
   111â†’			}
   112â†’
   113â†’			const body = documents.flatMap((doc) => {
   114â†’				const { _id, ...docWithoutId } = doc;
   115â†’				return [{ index: { _index: indexName, _id } }, docWithoutId];
   116â†’			});
   117â†’
   118â†’			const response = await this.client.bulk({ body });
   119â†’
   120â†’			const errorItems = response.body.items.filter(
   121â†’				(item: { index?: { error?: unknown } }) => item.index?.error,
   122â†’			);
   123â†’
   124â†’			const errors = errorItems.length;
   125â†’			const indexed = documents.length - errors;
   126â†’
   127â†’			if (errors > 0) {
   128â†’				this.logger.warn(
   129â†’					`Bulk index completed with ${errors} errors out of ${documents.length} documents`,
   130â†’				);
   131â†’
   132â†’				const sampleErrors = errorItems
   133â†’					.slice(0, 3)
   134â†’					.map((item: { index?: { error?: { type?: string; reason?: string } } }) => ({
   135â†’						type: item.index?.error?.type,
   136â†’						reason: item.index?.error?.reason,
   137â†’					}));
   138â†’
   139â†’				this.logger.error(`Sample errors: ${JSON.stringify(sampleErrors, null, 2)}`);
   140â†’			}
   141â†’
   142â†’			return { indexed, errors };
   143â†’		} catch (error: unknown) {
   144â†’			this.handleError({ context: 'Bulk index failed', error });
   145â†’			throw error;
   146â†’		}
   147â†’	}
